// Rainbow Ring Stacker — the classic children's stacking toy.
// A round base, a central tapered post, and a stack of N donut rings of
// decreasing radius climbing the post, each ring a different rainbow color.
const { Manifold, CrossSection } = api;

// ---- Customizer knobs -------------------------------------------------------
const p = api.params({
  rings: {
    type: 'int', default: 6, min: 3, max: 9, step: 1,
    label: 'Ring count', help: 'How many donut rings stack on the post.',
  },
  baseDiameter: {
    type: 'number', default: 70, min: 40, max: 120, step: 1, unit: 'mm',
    label: 'Base diameter',
  },
  baseHeight: {
    type: 'number', default: 9, min: 4, max: 20, step: 0.5, unit: 'mm',
    label: 'Base height',
  },
  ringTube: {
    type: 'number', default: 7, min: 3, max: 12, step: 0.5, unit: 'mm',
    label: 'Ring thickness', help: 'Tube (cross-section) radius of each donut.',
  },
  ringGap: {
    type: 'number', default: 2, min: 0, max: 8, step: 0.5, unit: 'mm',
    label: 'Gap between rings', help: 'Vertical breathing room between stacked rings.',
  },
  taper: {
    type: 'number', default: 0.78, min: 0.5, max: 1, step: 0.01,
    label: 'Post taper', help: 'Top post radius as a fraction of the bottom (1 = straight).',
  },
  topper: {
    type: 'boolean', default: true, label: 'Ball topper',
    help: 'Cap the post with a rounded ball.',
  },
});

// ---- Derived dimensions -----------------------------------------------------
const baseR = p.baseDiameter / 2;
const tube = p.ringTube;

// Post radius (bottom). Kept comfortably thinner than the smallest ring's hole
// so every ring threads onto the post and slides freely (the real toy), while
// the post itself overlaps the base (>= 0.5) and fuses into one molded piece.
const postRbot = Math.max(4, baseR * 0.14);
const postRtop = postRbot * p.taper;

// Per-ring fraction (0 at bottom → 1 at top), used to taper both the outer
// radius and (subtly) the tube so the stack reads as a clear rainbow cone.
const frac = (i) => (p.rings === 1 ? 0 : i / (p.rings - 1));
// Top ring's tube is a bit slimmer than the bottom's — strengthens the taper
// and keeps the crowning ring dainty.
const TUBE_TAPER = 0.3;
const ringTubeAt = (i) => tube * (1 - TUBE_TAPER * frac(i));

// Each ring's outer radius shrinks going up; bottom ring is the widest. Largest
// sits well inside the base rim; smallest is the post + its (slim) tube +
// headroom so even the top ring keeps an open hole that clears the post.
const maxOuter = baseR * 0.82;
const minOuter = postRtop + 2 * ringTubeAt(p.rings - 1) + 4;
const ringOuterR = (i) => maxOuter - (maxOuter - minOuter) * frac(i);

// One ring sits a tube-diameter tall; stack pitch adds the gap. Tube radius is
// fixed (the knob = real donut thickness) so the stack reads as clean, evenly
// thick rings of decreasing diameter.
const ringHeight = tube * 2;
const pitch = ringHeight + p.ringGap;

// Float the bottom ring above the base so it stays a free piece (a touching
// seam would fuse it into the base). Center height of ring i:
const baseClear = Math.max(p.ringGap, 1.5);
const ringZ = (i) => p.baseHeight + baseClear + i * pitch + ringHeight / 2;

// Post must clear the top ring plus headroom for the topper.
const stackTop = ringZ(p.rings - 1) + ringHeight / 2;
const postH = stackTop + tube * 2.5;

// Linear post radius at any height — used to keep each ring's hole just wider
// than the post so the rings slide on as free pieces.
const postRat = (z) => postRbot + (postRtop - postRbot) * (z / postH);

// Build the tapered post as a stand-alone labeled solid.
const post = api.label(
  Manifold.cylinder(postH, postRbot, postRtop).translate([0, 0, 0]),
  'post',
);

// Domed base: a disc with a softly rounded top edge (revolved rounded profile).
function makeBase() {
  const h = p.baseHeight;
  const fillet = Math.min(h * 0.6, baseR * 0.18);
  // Radial profile (X = radius, Y = height); rounded outer-top corner.
  const prof = CrossSection.ofPolygons([[
    [0, 0],
    [baseR, 0],
    [baseR, h - fillet],
    [baseR - fillet, h],
    [0, h],
  ]]);
  return api.label(prof.revolve(), 'base');
}
const base = makeBase();

// One donut ring with a given OUTER radius and tube radius, centered at height
// z. Like the real toy, each ring is a separate piece that slides onto the
// post: the hole = outer - 2*tubeR always clears the thin post, so rings are
// free components (not fused) and read as the classic stack-of-donuts. A safety
// min on the hole guarantees clearance even if a knob combo would close it.
const SLIDE = 0.6; // min clearance between hole and post wall (sliding fit)
function makeRing(outerR, tubeR, z) {
  const holeR = Math.max(outerR - 2 * tubeR, postRat(z) + SLIDE);
  const majorR = (outerR + holeR) / 2;                 // tube centerline radius
  const realTube = (outerR - holeR) / 2;               // donut tube radius
  return CrossSection.circle(realTube)
    .translate([majorR, 0])
    .revolve()
    .translate([0, 0, z]);                             // donut, Z-up, at height z
}

// Stack the rings up the post, widest at the bottom; each keeps its own label
// so it can be rainbow-painted.
const ringEntries = [];
for (let i = 0; i < p.rings; i++) {
  const ring = makeRing(ringOuterR(i), ringTubeAt(i), ringZ(i));
  ringEntries.push({ name: `ring${i}`, shape: api.label(ring, `ring${i}`) });
}

// Optional ball topper crowning the post.
const extras = [];
if (p.topper) {
  const ballR = postRtop + tube * 0.6;
  const ball = Manifold.sphere(ballR).translate([0, 0, postH - ballR * 0.35]);
  extras.push({ name: 'topper', shape: api.label(ball, 'topper') });
}

// Union everything into one returned Manifold; labels propagate through .add()
// so every region stays paintable. base + post (+ topper) overlap → one fused
// stand; the rings are intentionally separate free pieces, so the result has
// `rings + 1` components — the molded stand plus N slide-on donuts.
const parts = [
  { name: 'base', shape: base },
  { name: 'post', shape: post },
  ...ringEntries,
  ...extras,
];
return api.labeledUnion(parts);

